```

Canvas абсолютно поверх img. JS логика стирания:
- Курсор скрыт (`cursor: none`) на всей странице
- Кастомный курсор — маленький белый круг через div который следует за мышью
- При mousemove на canvas — рисуем белым radial gradient (размер кисти 100px)
- `globalCompositeOperation = 'source-over'`
- Touch support (touchmove тоже)

JS код для стирания (вставь в `<script>` тег компонента):
```javascript
const canvas = document.getElementById('eraseCanvas');
const ctx = canvas.getContext('2d');
const wrapper = canvas.parentElement;

function resizeCanvas() {
  canvas.width = wrapper.offsetWidth;
  canvas.height = wrapper.offsetHeight;
}
resizeCanvas();
window.addEventListener('resize', resizeCanvas);

let isErasing = false;

function erase(x, y) {
  const brushSize = 100;
  const gradient = ctx.createRadialGradient(x, y, 0, x, y, brushSize);
  gradient.addColorStop(0, 'rgba(255,255,255,1)');
  gradient.addColorStop(0.5, 'rgba(255,255,255,0.8)');
  gradient.addColorStop(1, 'rgba(255,255,255,0)');
  ctx.fillStyle = gradient;
  ctx.beginPath();
  ctx.arc(x, y, brushSize, 0, Math.PI * 2);
  ctx.fill();
}

canvas.addEventListener('mousemove', (e) => {
  const rect = canvas.getBoundingClientRect();
  erase(e.clientX - rect.left, e.clientY - rect.top);
});

canvas.addEventListener('touchmove', (e) => {
  e.preventDefault();
  const rect = canvas.getBoundingClientRect();
  const touch = e.touches[0];
  erase(touch.clientX - rect.left, touch.clientY - rect.top);
}, { passive: false });

// Кастомный курсор
const cursor = document.createElement('div');
cursor.id = 'custom-cursor';
document.body.appendChild(cursor);
document.addEventListener('mousemove', (e) => {
  cursor.style.left = e.clientX + 'px';
  cursor.style.top = e.clientY + 'px';
});
```

